function dateToDayOff(s){const base=new Date("2026-01-01"),d=new Date(s);return Math.round((d-base)/86400000);}
function dayToWeek(d){const dt=new Date("2026-01-01");dt.setDate(dt.getDate()+d);const y=dt.getFullYear(),soy=new Date(y,0,1);const wk=Math.ceil(((dt-soy)/86400000+soy.getDay()+1)/7);return `${y}-W${String(wk).padStart(2,"0")}`;}
function dayToMonth(d){const dt=new Date("2026-01-01");dt.setDate(dt.getDate()+d);return `${dt.getFullYear()}-${String(dt.getMonth()+1).padStart(2,"0")}`;}

function computeAgg(rows){
  const sum={total:0,positive:0,negative:0,neutral:0,total_interactions:0};
  const wk={},mo={},byCh=new Array(9).fill(0),byLbl=new Array(16).fill(0);
  for(const [day,ti,ci,si,li] of rows){
    sum.total++;
    if(si===0)sum.positive++; else if(si===1)sum.negative++; else sum.neutral++;
    const w=dayToWeek(day);
    if(!wk[w])wk[w]={week:w,total:0,Positive:0,Negative:0,Neutral:0};
    wk[w].total++;
    if(si===0)wk[w].Positive++; else if(si===1)wk[w].Negative++; else wk[w].Neutral++;
    const m=dayToMonth(day);
    if(!mo[m])mo[m]={month:m,total:0,positive:0,negative:0,neutral:0};
    mo[m].total++;
    if(si===0)mo[m].positive++; else if(si===1)mo[m].negative++; else mo[m].neutral++;
    if(ci>=0&&ci<9)byCh[ci]++;
    if(li>=0&&li<16)byLbl[li]++;
  }
  const nsr_monthly=Object.values(mo).sort((a,b)=>a.month<b.month?-1:1).map(m=>{
    const n=m.total>0?+((m.positive-m.negative)/m.total*100).toFixed(1):0;
    return {...m,nsr:n};
  });
  const trend_weekly=Object.values(wk).sort((a,b)=>a.week<b.week?-1:1);
  const channels_obj={};
  META.channels.forEach((c,i)=>{if(byCh[i]>0)channels_obj[c]={total:byCh[i]};});
  const top_labels=META.labels.map((l,i)=>({label:l,count:byLbl[i]})).filter(x=>x.count>0).sort((a,b)=>b.count-a.count);
  return {summary:sum,trend_weekly,nsr_monthly,channels:channels_obj,top_labels};
}

const FilterCtx=React.createContext(null);
function FilterProvider({children}){
  const [draft,setDraft]=useState({dateFrom:"2026-01-01",dateTo:"2026-05-31",channel:-1,topic:-1,label:-1,sentiment:-1});
  const [applied,setApplied]=useState({dateFrom:"2026-01-01",dateTo:"2026-05-31",channel:-1,topic:-1,label:-1,sentiment:-1});
  const applyFilters=()=>setApplied({...draft});
  const resetFilters=()=>{const d={dateFrom:"2026-01-01",dateTo:"2026-05-31",channel:-1,topic:-1,label:-1,sentiment:-1};setDraft(d);setApplied(d);};
  const filteredRows=React.useMemo(()=>{
    const fd=dateToDayOff(applied.dateFrom),td=dateToDayOff(applied.dateTo);
    return ALL_ROWS.filter(([day,ti,ci,si,li])=>{
      if(day<fd||day>td)return false;
      if(applied.channel>=0&&ci!==applied.channel)return false;
      if(applied.topic>=0&&ti!==applied.topic)return false;
      if(applied.label>=0&&li!==applied.label)return false;
      if(applied.sentiment>=0&&si!==applied.sentiment)return false;
      return true;
    });
  },[applied]);
  const agg=React.useMemo(()=>computeAgg(filteredRows),[filteredRows]);
  return React.createElement(FilterCtx.Provider,{value:{draft,setDraft,applyFilters,resetFilters,agg,applied,filteredRows}},children);
}
const useFC=()=>React.useContext(FilterCtx);
