const fmt = n => n>=1e6?(n/1e6).toFixed(1)+"M":n>=1e3?(n/1e3).toFixed(1)+"K":String(n||0);
const pct = (n,t) => t?((n/t)*100).toFixed(1)+"%":"0%";
const nsr = (p,n,t) => t?(((p-n)/t)*100).toFixed(1):"0";
const fmtW = s => { if(!s)return""; const p=s.split("-"); return(p[2]||"")+"/"+(p[1]||""); };
const fmtM = s => { if(!s)return""; const[,m]=s.split("-"); return["","T1","T2","T3","T4","T5","T6","T7","T8","T9","T10","T11","T12"][+m]||s; };

