// ── REPORT ────────────────────────────────────────────────────────────────────
function ReportPage(){
  const s=RAW.summary;
  const nsrT=RAW.nsr_monthly.map(e=>e.nsr);
  const nsrUp=nsrT.length>1&&nsrT[nsrT.length-1]>nsrT[0];
  const topCh=Object.entries(RAW.channels).sort((a,b)=>b[1].total-a[1].total)[0];
  const topLbl=RAW.top_labels[0];
  return(
    <div style={{flex:1,overflow:"auto",background:T.bg,padding:"18px 20px"}}>
      <div style={{maxWidth:960,margin:"0 auto"}}>
        <Card style={{padding:36}}>
          <div style={{textAlign:"center",marginBottom:32,paddingBottom:24,borderBottom:"2px solid "+T.border}}>
            <div style={{width:60,height:60,borderRadius:14,background:"linear-gradient(135deg,#1877C8,#143F72)",color:"#fff",fontSize:20,fontWeight:900,display:"flex",alignItems:"center",justifyContent:"center",margin:"0 auto 12px"}}>M</div>
            <div style={{fontSize:24,fontWeight:900,color:T.navyDark}}>BÁO CÁO SOCIAL LISTENING</div>
            <div style={{fontSize:14,color:T.textSub,marginTop:4}}>Masan Group (MSN) · 2026</div>
          </div>
          <section style={{marginBottom:28}}>
            <div style={{fontSize:15,fontWeight:700,color:T.navy,marginBottom:14,paddingBottom:6,borderBottom:"2px solid "+T.navy+"22"}}>I. TỔNG QUAN THẢO LUẬN</div>
            <div style={{display:"flex",gap:10,marginBottom:14}}>
              <Stat label="Tổng bài đăng" value={fmt(s.total)}/><Stat label="Tích cực" value={pct(s.positive,s.total)} color={T.positive}/><Stat label="Tiêu cực" value={pct(s.negative,s.total)} color={T.negative}/><Stat label="Tương tác" value={fmt(s.total_interactions)}/>
            </div>
            <div style={{background:T.peach,borderRadius:8,padding:"14px 18px",fontSize:13,lineHeight:1.8,color:"#4A2A0A"}}>
              Masan Group ghi nhận <b>{fmt(s.total)}</b> thảo luận. Kênh <b>{topCh?.[0]}</b> chiếm tỷ trọng cao nhất ({pct(topCh?.[1]?.total||0,s.total)}). Chủ đề <b>"{topLbl?.label}"</b> được đề cập nhiều nhất ({fmt(topLbl?.count||0)} bài). NSR có xu hướng <b style={{color:nsrUp?T.positive:T.negative}}>{nsrUp?"cải thiện":"giảm"}</b>.
            </div>
          </section>
          <section style={{marginBottom:28}}>
            <div style={{fontSize:15,fontWeight:700,color:T.navy,marginBottom:14,paddingBottom:6,borderBottom:"2px solid "+T.navy+"22"}}>II. NSR THEO THÁNG</div>
            <ResponsiveContainer width="100%" height={200}>
              <ComposedChart data={RAW.nsr_monthly}><CartesianGrid strokeDasharray="3 3" stroke="#EAF0F8" vertical={false}/><XAxis dataKey="month" tickFormatter={fmtM} tick={{fontSize:11,fill:T.textSub}} tickLine={false} axisLine={{stroke:T.border}}/><YAxis tick={{fontSize:11,fill:T.textSub}} tickLine={false} axisLine={false}/><Tooltip content={<CT/>}/><Bar dataKey="nsr" name="NSR %" radius={[4,4,0,0]}>{RAW.nsr_monthly.map((e,i)=><Cell key={i} fill={e.nsr>=0?T.positive:T.negative}/>)}</Bar><Line type="monotone" dataKey="nsr" stroke={T.navy} strokeWidth={2} dot={{fill:T.navy,r:3}}/></ComposedChart>
            </ResponsiveContainer>
          </section>
          <section>
            <div style={{fontSize:15,fontWeight:700,color:T.navy,marginBottom:14,paddingBottom:6,borderBottom:"2px solid "+T.navy+"22"}}>III. RỦI RO TRUYỀN THÔNG</div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14}}>
              <div style={{background:"#FEF9F9",border:"1px solid "+T.negative+"33",borderRadius:8,padding:"14px 18px"}}><div style={{fontWeight:700,color:T.negative,fontSize:13,marginBottom:8}}>⚠️ Điểm rủi ro</div><div style={{fontSize:13,lineHeight:1.9}}>• Tổng <b>{fmt(RAW.negative.total)}</b> bài tiêu cực ({pct(RAW.negative.total,s.total)})<br/>• Level 3: <b>{RAW.negative.by_level["3"]||0}</b> bài<br/>• Level 2: <b>{fmt(RAW.negative.by_level["2"]||0)}</b> bài<br/>• Chủ đề: <b>{RAW.negative.topics[0]?.topic||""}</b></div></div>
              <div style={{background:"#F0FDF4",border:"1px solid "+T.positive+"33",borderRadius:8,padding:"14px 18px"}}><div style={{fontWeight:700,color:T.positive,fontSize:13,marginBottom:8}}>✅ Điểm tích cực</div><div style={{fontSize:13,lineHeight:1.9}}>• BOD: <b>{fmt(RAW.bod.total)}</b> thảo luận<br/>• IR: <b>{fmt(RAW.ir.total)}</b> thảo luận cổ phiếu<br/>• Facebook chiếm {pct(RAW.channels.Facebook?.total||0,s.total)}<br/>• Tương tác: <b>{fmt(s.total_interactions)}</b></div></div>
            </div>
          </section>
          <div style={{textAlign:"center",padding:"14px 0",marginTop:24,borderTop:"1px solid "+T.border,color:T.textLight,fontSize:11}}>Masan Group · Powered by Kompa AI Social Listening</div>
        </Card>
      </div>
    </div>
  );
}

